#include <iostream>

class Box {
public:
    int side;
    int volume() { return side * side * side; }
};

int main() {
    Box a;
    a.side = 3;
    Box b;
    b.side = 2;
    a.side = 4;
    std::cout << a.volume() << "\n";
    std::cout << b.volume() << "\n";
}
```

